                <CardTitle className="text-base">{user.displayName}</CardTitle>
                <CardDescription className="truncate text-xs">{user.email}</CardDescription>
              </div>
              <Link to={userProfile.url} className="text-xs font-medium text-primary hover:underline">
                Profiel
              </Link>
            </CardHeader>
            <CardContent className="space-y-2 pt-0">
              {user.role ? (
                <Badge variant="secondary" className="font-normal">
                  {user.role}
                </Badge>
              ) : null}
            </CardContent>
          </Card>
        ) : null}

        {user && activeOrganization ? (
          <Card className="col-span-12 border-border/80 bg-card/80 shadow-sm sm:col-span-6 lg:col-span-8">
            <CardHeader className="pb-2">
              <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
                <div>
                  <CardDescription className="text-[10px] font-semibold uppercase tracking-wide">
