                  <CardTitle className="mt-1 text-lg">{activeOrganization.name}</CardTitle>
                  <p className="text-xs text-muted-foreground">Organisatie-ID: {activeOrganization.id}</p>
                </div>
                <Link to={orgProfile.url} className="text-xs font-medium text-primary hover:underline sm:pt-1">
                  Organisatieprofiel
                </Link>
              </div>
            </CardHeader>
            <CardContent className="space-y-2 pt-0 text-sm text-muted-foreground">
              {user.representedOrganization.id !== activeOrganization.id ? (
                <p>
                  <span className="font-medium text-foreground">Vertegenwoordigt:</span>{" "}
                  {user.representedOrganization.name}
                </p>
              ) : (
                <p>
                  <span className="font-medium text-foreground">Vertegenwoordigt:</span>{" "}
                  {user.representedOrganization.name}
                </p>
              )}
