import type { ComponentProps, ReactNode } from "react";

import { cn } from "@/lib/utils";

import { H1 } from "@procertus-ui/ui";

function isTextNode(node: ReactNode): node is string | number {
  return typeof node === "string" || typeof node === "number";
}

/** Small uppercase eyebrow above the page title (slot). */
export function PageHeaderKicker({ className, ...props }: ComponentProps<"p">) {
  return (
    <p
      data-slot="page-header-kicker"
      className={cn(
        "text-[10px] font-semibold uppercase tracking-[0.2em] text-muted-foreground",
        className,
      )}
      {...props}
    />
  );
}

/** Muted supporting copy under the title (slot). */
export function PageHeaderDescription({ className, ...props }: ComponentProps<"p">) {
  return (
    <p
      data-slot="page-header-description"
      className={cn("leading-relaxed text-muted-foreground", className)}
      {...props}
    />
  );
}

/** Right-hand column for logos or hero media (slot). */
export function PageHeaderMedia({ className, ...props }: ComponentProps<"div">) {
  return (
    <div
      data-slot="page-header-media"
      className={cn("flex shrink-0 items-center justify-start sm:justify-end", className)}
      {...props}
    />
  );
}

/** Row under the description for buttons or links (slot). */
export function PageHeaderActions({ className, ...props }: ComponentProps<"div">) {
  return (
    <div
      data-slot="page-header-actions"
      className={cn("flex flex-wrap gap-component pt-micro", className)}
      {...props}
    />
  );
}

export type PageHeaderProps = Omit<ComponentProps<"header">, "title"> & {
  /** Small label above the title; strings are wrapped in {@link PageHeaderKicker}. */
  kicker?: ReactNode;
  /** Primary heading; plain text is wrapped in {@link H1}, otherwise pass your own heading node. */
  title: ReactNode;
  /** Supporting copy; strings are wrapped in {@link PageHeaderDescription}. */
  description?: ReactNode;
  /** Logo or illustration; placed in {@link PageHeaderMedia} on larger breakpoints. */
  media?: ReactNode;
  /** Toolbar row under the description (e.g. buttons). */
  actions?: ReactNode;
};

function renderKicker(kicker: ReactNode | undefined) {
  if (kicker == null) return null;
  if (isTextNode(kicker)) return <PageHeaderKicker>{kicker}</PageHeaderKicker>;
  return kicker;
}

function renderDescription(description: ReactNode | undefined) {
  if (description == null) return null;
  if (isTextNode(description)) return <PageHeaderDescription>{description}</PageHeaderDescription>;
  return description;
}

function renderTitle(title: ReactNode) {
  if (isTextNode(title)) return <H1>{title}</H1>;
  return title;
}

/**
 * Presentational page masthead: optional kicker, title, description, actions, and trailing media.
 * Use {@link PageHeaderKicker}, {@link PageHeaderDescription}, and {@link PageHeaderMedia} when you
 * need full control over slot markup while keeping typography consistent.
 */
export function PageHeader({
  className,
  kicker,
  title,
  description,
  media,
  actions,
  ...props
}: PageHeaderProps) {
  return (
    <header className={cn("pb-region", className)} {...props}>
      <div className="flex flex-col gap-region sm:flex-row sm:items-end sm:justify-between">
        <div className="flex min-w-0 flex-col gap-micro text-left">
          {renderKicker(kicker)}
          {renderTitle(title)}
          {renderDescription(description)}
          {actions != null ? <PageHeaderActions>{actions}</PageHeaderActions> : null}
        </div>
        {media != null ? <PageHeaderMedia>{media}</PageHeaderMedia> : null}
      </div>
    </header>
  );
}

export {
  PageHeader,
  PageHeaderActions,
  PageHeaderDescription,
  PageHeaderKicker,
  PageHeaderMedia,
} from "./PageHeader";
export type { PageHeaderProps } from "./PageHeader";

