import { HugeiconsIcon } from "@hugeicons/react";
import type { CustomerContext } from "@procertus-ui/ui-certification";
import { ONBOARDING_FLOW_STORAGE_KEY } from "@procertus-ui/ui-certification";
import {
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  H1,
  iconStroke,
  Input,
  Label,
} from "@procertus-ui/ui";
import { PageHeader } from "@procertus-ui/ui-lib";
import { useMockPrototypePatchProfile, useMockPrototypeSession } from "@procertus-ui/ui-pt1-prototype";
import { useEffect, useMemo, useState } from "react";

import { mergeStoredOnboardingCustomerContext } from "../features/profile/mergeStoredOnboardingCustomerContext";
import { customerContextsEqual, readStoredOnboardingContexts } from "../features/profile/readStoredOnboardingContext";
import { PROTOTYPE_PRIMARY_NAV } from "../navConfig";
import { DataRow } from "./profile/DataRow";

const userNav = PROTOTYPE_PRIMARY_NAV.find((item) => item.key === "user-profile")!;

const emptyContextFields: Pick<
  CustomerContext,
  | "representativeFirstName"
  | "representativeLastName"
  | "representativeTitlePreset"
  | "representativeTitle"
  | "representativeEmail"
  | "representativeRolePreset"
  | "representativeRole"
> = {
  representativeFirstName: "",
  representativeLastName: "",
  representativeTitlePreset: "",
  representativeTitle: "",
  representativeEmail: "",
  representativeRolePreset: "",
  representativeRole: "",
};

type UserEditForm = {
  displayName: string;
  email: string;
  role: string;
  homeOrgName: string;
  reprOrgName: string;
} & typeof emptyContextFields;

function onboardingSlice(ctx: Partial<CustomerContext> | null | undefined) {
  return {
    representativeFirstName: ctx?.representativeFirstName ?? "",
    representativeLastName: ctx?.representativeLastName ?? "",
    representativeTitlePreset: ctx?.representativeTitlePreset ?? "",
    representativeTitle: ctx?.representativeTitle ?? "",
    representativeEmail: ctx?.representativeEmail ?? "",
    representativeRolePreset: ctx?.representativeRolePreset ?? "",
    representativeRole: ctx?.representativeRole ?? "",
  };
}

function OnboardingPersonRows({ context }: { context: CustomerContext }) {
  return (
    <>
      <DataRow label="Voornaam" value={context.representativeFirstName} />
      <DataRow label="Achternaam" value={context.representativeLastName} />
      <DataRow label="Aanhef (preset-id)" value={context.representativeTitlePreset} />
      <DataRow label="Aanhef (tekst)" value={context.representativeTitle} />
      <DataRow label="E-mail" value={context.representativeEmail} />
      <DataRow label="Functie (preset-id)" value={context.representativeRolePreset} />
      <DataRow label="Functie (label)" value={context.representativeRole} />
    </>
  );
}

export function UserProfilePage() {
  const session = useMockPrototypeSession();
  const user = session?.user;
  const patchProfile = useMockPrototypePatchProfile();
  const [storedTick, setStoredTick] = useState(0);
  const stored = useMemo(() => readStoredOnboardingContexts(), [storedTick]);
  const [editOpen, setEditOpen] = useState(false);
  const [form, setForm] = useState<UserEditForm | null>(null);

  useEffect(() => {
    if (!editOpen || !user) return;
    const flow = stored.flowContext;
    const snap = stored.completedSnapshotContext;
    const ctx = flow ?? snap ?? {};
    setForm({
      displayName: user.displayName,
      email: user.email,
      role: user.role ?? "",
      homeOrgName: user.homeOrganization.name,
      reprOrgName: user.representedOrganization.name,
      ...onboardingSlice(ctx),
    });
  }, [editOpen, user, stored]);

  const leadingIcon = (
    <div className="flex size-10 shrink-0 items-center justify-center rounded-xl bg-primary/8 text-primary">
      <HugeiconsIcon icon={userNav.icon} size={22} strokeWidth={iconStroke(22)} />
    </div>
  );

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !form) return;
    patchProfile({
      user: {
        displayName: form.displayName,
        email: form.email,
        role: form.role,
      },
      organizationNames: {
        [user.homeOrganization.id]: form.homeOrgName,
        [user.representedOrganization.id]: form.reprOrgName,
      },
    });
    mergeStoredOnboardingCustomerContext({
      representativeFirstName: form.representativeFirstName,
      representativeLastName: form.representativeLastName,
      representativeTitlePreset: form.representativeTitlePreset,
      representativeTitle: form.representativeTitle,
      representativeEmail: form.representativeEmail,
      representativeRolePreset: form.representativeRolePreset,
      representativeRole: form.representativeRole,
    });
    setStoredTick((n) => n + 1);
    setEditOpen(false);
  };

  return (
    <div className="flex w-full max-w-[1400px] flex-col gap-region px-4 py-6 text-left md:px-6 md:py-8">
      <PageHeader
        leading={leadingIcon}
        kicker="Mijn account"
        title={<H1>Mijn profiel</H1>}
        description="Gegevens van uw prototype-sessie en — indien aanwezig — de velden uit de anonieme onboardingflow (localStorage in deze browser)."
        actions={
          user ? (
            <Button type="button" size="sm" variant="outline" onClick={() => setEditOpen(true)}>
              Gegevens bewerken
            </Button>
          ) : null
        }
      />

