import { HugeiconsIcon } from "@hugeicons/react";
import type { CustomerContext } from "@procertus-ui/ui-certification";
import { ONBOARDING_FLOW_STORAGE_KEY } from "@procertus-ui/ui-certification";
import {
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  H1,
  iconStroke,
  Input,
  Label,
} from "@procertus-ui/ui";
import { PageHeader } from "@procertus-ui/ui-lib";
import { useMockPrototypePatchProfile, useMockPrototypeSession } from "@procertus-ui/ui-pt1-prototype";
import { useEffect, useMemo, useState } from "react";

import { mergeStoredOnboardingCustomerContext } from "../features/profile/mergeStoredOnboardingCustomerContext";
import { customerContextsEqual, readStoredOnboardingContexts } from "../features/profile/readStoredOnboardingContext";
import { resolveOrgDemoAddress, setOrgDemoAddressOverride } from "../features/profile/prototypeOrgDemoAddresses";
import { mockOrganizationAddress, mockOrganizationUserCount } from "./dashboard-mock-data";
import { PROTOTYPE_PRIMARY_NAV } from "../navConfig";
import { DataRow } from "./profile/DataRow";

const orgNav = PROTOTYPE_PRIMARY_NAV.find((item) => item.key === "organization-profile")!;

type OrgEditForm = {
  orgName: string;
  demoAddress: string;
  organizationName: string;
  vatNumber: string;
  country: string;
  addressStreet: string;
  addressHouseNumber: string;
  addressPostalCode: string;
  addressCity: string;
};

function companySlice(ctx: Partial<CustomerContext> | null | undefined): Omit<OrgEditForm, "orgName" | "demoAddress"> {
  return {
    organizationName: ctx?.organizationName ?? "",
    vatNumber: ctx?.vatNumber ?? "",
    country: ctx?.country ?? "",
    addressStreet: ctx?.addressStreet ?? "",
    addressHouseNumber: ctx?.addressHouseNumber ?? "",
    addressPostalCode: ctx?.addressPostalCode ?? "",
    addressCity: ctx?.addressCity ?? "",
  };
}

function OnboardingCompanyRows({ context }: { context: CustomerContext }) {
  return (
    <>
      <DataRow label="Bedrijfsnaam" value={context.organizationName} />
      <DataRow label="BTW-nummer" value={context.vatNumber} />
      <DataRow label="Land (herkomst)" value={context.country} />
      <DataRow label="Straat" value={context.addressStreet} />
      <DataRow label="Huisnummer" value={context.addressHouseNumber} />
      <DataRow label="Postcode" value={context.addressPostalCode} />
      <DataRow label="Plaats" value={context.addressCity} />
    </>
  );
}

export function OrganizationProfilePage() {
  const session = useMockPrototypeSession();
  const active = session?.activeOrganization;
  const user = session?.user;
  const patchProfile = useMockPrototypePatchProfile();
  const [storedTick, setStoredTick] = useState(0);
  const stored = useMemo(() => readStoredOnboardingContexts(), [storedTick]);
  const [editOpen, setEditOpen] = useState(false);
  const [form, setForm] = useState<OrgEditForm | null>(null);

  const activeAddress = active
    ? resolveOrgDemoAddress(active.id, mockOrganizationAddress(active.id))
    : null;
  const activeUserCount = active ? mockOrganizationUserCount(active.id) : null;

  useEffect(() => {
    if (!editOpen || !active) return;
    const flow = stored.flowContext;
    const snap = stored.completedSnapshotContext;
    const ctx = flow ?? snap ?? {};
    setForm({
      orgName: active.name,
      demoAddress: resolveOrgDemoAddress(active.id, mockOrganizationAddress(active.id)),
      ...companySlice(ctx),
    });
  }, [editOpen, active, stored]);

  const leadingIcon = (
    <div className="flex size-10 shrink-0 items-center justify-center rounded-xl bg-primary/8 text-primary">
      <HugeiconsIcon icon={orgNav.icon} size={22} strokeWidth={iconStroke(22)} />
    </div>
  );

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!active || !form) return;
    patchProfile({
      organizationNames: { [active.id]: form.orgName },
    });
    setOrgDemoAddressOverride(active.id, form.demoAddress);
    mergeStoredOnboardingCustomerContext({
      organizationName: form.organizationName,
      vatNumber: form.vatNumber,
      country: form.country,
      addressStreet: form.addressStreet,
      addressHouseNumber: form.addressHouseNumber,
      addressPostalCode: form.addressPostalCode,
      addressCity: form.addressCity,
    });
    setStoredTick((n) => n + 1);
    setEditOpen(false);
  };

  return (
    <div className="flex w-full max-w-[1400px] flex-col gap-region px-4 py-6 text-left md:px-6 md:py-8">
      <PageHeader
        leading={leadingIcon}
        kicker="Organisatie"
        title={<H1>Organisatieprofiel</H1>}
        description="Actieve werkruimte uit de sessie, gerelateerde organisaties, prototype-adres en — indien aanwezig — bedrijfsvelden uit de onboardingflow (localStorage)."
        actions={
          active ? (
            <Button type="button" size="sm" variant="outline" onClick={() => setEditOpen(true)}>
              Gegevens bewerken
            </Button>
          ) : null
        }
      />

      <Dialog open={editOpen} onOpenChange={setEditOpen}>
        <DialogContent className="max-h-[min(90vh,720px)] overflow-y-auto sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Organisatie bewerken</DialogTitle>
            <DialogDescription>
              Wijzigingen gelden voor deze demo (sessie, adresoverride in localStorage, onboarding-context).
            </DialogDescription>
          </DialogHeader>
          {form && active ? (
            <form onSubmit={handleSave} className="grid gap-4 py-2">
              <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Actieve organisatie</p>
              <div className="grid gap-2">
                <Label htmlFor="of-id">Organisatie-id</Label>
                <Input id="of-id" value={active.id} readOnly className="bg-muted/50" />
              </div>
              <div className="grid gap-2">
                <Label htmlFor="of-name">Naam (sessie)</Label>
                <Input
                  id="of-name"
                  value={form.orgName}
                  onChange={(ev) => setForm((f) => (f ? { ...f, orgName: ev.target.value } : f))}
                />
              </div>
              <div className="grid gap-2">
                <Label htmlFor="of-addr">Adres (demo)</Label>
                <Input
                  id="of-addr"
                  value={form.demoAddress}
                  onChange={(ev) => setForm((f) => (f ? { ...f, demoAddress: ev.target.value } : f))}
                />
              </div>
              <div className="grid gap-2">
                <Label htmlFor="of-users">Gebruikers in directory (demo)</Label>
                <Input
                  id="of-users"
                  value={String(mockOrganizationUserCount(active.id))}
                  readOnly
                  className="bg-muted/50"
                />
              </div>

              <p className="pt-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                Bedrijf (onboarding)
              </p>
              <div className="grid gap-2">
                <Label htmlFor="of-on">Bedrijfsnaam</Label>
                <Input
                  id="of-on"
                  value={form.organizationName}
                  onChange={(ev) => setForm((f) => (f ? { ...f, organizationName: ev.target.value } : f))}
                />
              </div>
              <div className="grid gap-2 sm:grid-cols-2">
                <div className="grid gap-2">
                  <Label htmlFor="of-vat">BTW-nummer</Label>
                  <Input
                    id="of-vat"
                    value={form.vatNumber}
                    onChange={(ev) => setForm((f) => (f ? { ...f, vatNumber: ev.target.value } : f))}
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="of-country">Land</Label>
                  <Input
                    id="of-country"
                    value={form.country}
                    onChange={(ev) => setForm((f) => (f ? { ...f, country: ev.target.value } : f))}
                  />
                </div>
              </div>
              <div className="grid gap-2 sm:grid-cols-2">
                <div className="grid gap-2">
                  <Label htmlFor="of-st">Straat</Label>
                  <Input
                    id="of-st"
                    value={form.addressStreet}
                    onChange={(ev) => setForm((f) => (f ? { ...f, addressStreet: ev.target.value } : f))}
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="of-hn">Huisnummer</Label>
                  <Input
                    id="of-hn"
                    value={form.addressHouseNumber}
                    onChange={(ev) => setForm((f) => (f ? { ...f, addressHouseNumber: ev.target.value } : f))}
                  />
                </div>
              </div>
              <div className="grid gap-2 sm:grid-cols-2">
                <div className="grid gap-2">
                  <Label htmlFor="of-pc">Postcode</Label>
                  <Input
                    id="of-pc"
                    value={form.addressPostalCode}
                    onChange={(ev) => setForm((f) => (f ? { ...f, addressPostalCode: ev.target.value } : f))}
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="of-city">Plaats</Label>
                  <Input
                    id="of-city"
                    value={form.addressCity}
                    onChange={(ev) => setForm((f) => (f ? { ...f, addressCity: ev.target.value } : f))}
                  />
                </div>
              </div>

              <DialogFooter className="gap-2 sm:gap-0">
                <Button type="button" variant="outline" onClick={() => setEditOpen(false)}>
                  Annuleren
                </Button>
                <Button type="submit">Opslaan</Button>
              </DialogFooter>
            </form>
          ) : null}
        </DialogContent>
      </Dialog>

      {active ? (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Actieve organisatie</CardTitle>
            <CardDescription>Huidige werkruimte in het prototype.</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col">
            <DataRow label="Naam" value={active.name} />
            <DataRow label="Id" value={active.id} />
            <DataRow label="Adres (demo)" value={activeAddress} />
            <DataRow label="Gebruikers in directory (demo)" value={activeUserCount} />
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="py-6 text-sm text-muted-foreground">Geen actieve organisatie in de sessie.</CardContent>
        </Card>
      )}

      {user ? (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Context uit uw account</CardTitle>
            <CardDescription>Thuis- versus vertegenwoordigde organisatie (mock).</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col">
            <DataRow label="Thuisorganisatie" value={`${user.homeOrganization.name} (${user.homeOrganization.id})`} />
            <DataRow
              label="Vertegenwoordigde organisatie"
              value={`${user.representedOrganization.name} (${user.representedOrganization.id})`}
            />
          </CardContent>
        </Card>
      ) : null}

      {session?.organizations?.length ? (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Beschikbare organisaties</CardTitle>
            <CardDescription>Lijst zoals geleverd door de mock-auth (wisselen via shell).</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col">
            {session.organizations.map((org) => (
              <DataRow
                key={org.id}
                label={org.id === session.activeOrganization.id ? `${org.name} (actief)` : org.name}
                value={org.id}
              />
            ))}
          </CardContent>
        </Card>
      ) : null}

      <Card>
        <CardHeader>
          <CardTitle className="text-base">Bedrijf (onboardingflow)</CardTitle>
          <CardDescription>
            Velden uit stap &quot;Bedrijf&quot; / BTW-zoeksimulatie in{" "}
            <code className="rounded bg-muted px-1 py-0.5 text-xs">anonymous-onboarding-flow-view</code> — zelfde{" "}
            <code className="rounded bg-muted px-1 py-0.5 text-xs">CustomerContext</code> als bij het aanvraagpakket.
          </CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col">
          {stored.flowContext || stored.completedSnapshotContext ? (
            <>
              {stored.flowContext ? (
                <>
                  <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                    Laatste flow-state ({ONBOARDING_FLOW_STORAGE_KEY})
                  </p>
                  <OnboardingCompanyRows context={stored.flowContext} />
                </>
              ) : null}
              {stored.completedSnapshotContext &&
              (!stored.flowContext ||
                !customerContextsEqual(stored.flowContext, stored.completedSnapshotContext)) ? (
                <>
                  <p
                    className={
                      stored.flowContext
                        ? "mb-2 mt-4 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
                        : "mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
