import { HugeiconsIcon } from "@hugeicons/react";
import type { CustomerContext } from "@procertus-ui/ui-certification";
import { ONBOARDING_FLOW_STORAGE_KEY } from "@procertus-ui/ui-certification";
import {
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  Field,
  FieldContent,
  FieldDescription,
  FieldLabel,
  H1,
  iconStroke,
  Input,
} from "@procertus-ui/ui";
import { OnboardingStepper, PageHeader, StepLayout, useStepLayout, type OnboardingStepperStep } from "@procertus-ui/ui-lib";
import {
  type MockPrototypeUser,
  type PrototypeUserProfile,
  useMockPrototypePatchProfile,
  useMockPrototypeSession,
} from "@procertus-ui/ui-pt1-prototype";
import { useCallback, useEffect, useMemo, useState } from "react";

import { mergeStoredOnboardingCustomerContext } from "../features/profile/mergeStoredOnboardingCustomerContext";
import {
  customerContextsEqual,
  readStoredOnboardingContexts,
  type StoredOnboardingContexts,
} from "../features/profile/readStoredOnboardingContext";
import { PROTOTYPE_PRIMARY_NAV } from "../navConfig";
import { DataRow } from "./profile/DataRow";

const userNav = PROTOTYPE_PRIMARY_NAV.find((item) => item.key === "user-profile")!;

const USER_EDIT_STEPS: OnboardingStepperStep[] = [
  { id: "identity", title: "Identiteit" },
  { id: "contact", title: "Contact & werk" },
  { id: "orgs", title: "Organisaties" },
  { id: "representative", title: "Vertegenwoordiger" },
];

type OnboardingFormFields = ReturnType<typeof onboardingSlice>;

type UserEditForm = Omit<PrototypeUserProfile, "id"> & {
  homeOrgName: string;
  reprOrgName: string;
} & OnboardingFormFields;

function onboardingSlice(ctx: Partial<CustomerContext> | null | undefined) {
  return {
    representativeFirstName: ctx?.representativeFirstName ?? "",
    representativeLastName: ctx?.representativeLastName ?? "",
    representativeTitlePreset: ctx?.representativeTitlePreset ?? "",
    representativeTitle: ctx?.representativeTitle ?? "",
    representativeEmail: ctx?.representativeEmail ?? "",
    representativeRolePreset: ctx?.representativeRolePreset ?? "",
    representativeRole: ctx?.representativeRole ?? "",
  };
}

function resolveProfilePageTitle(user: MockPrototypeUser | undefined, stored: StoredOnboardingContexts): string {
  if (user) {
    const fromParts = `${user.givenName} ${user.familyName}`.trim();
    if (fromParts.length > 0) return fromParts;
    const d = user.displayName.trim();
    if (d.length > 0) return d;
  }
  const ctx = stored.flowContext ?? stored.completedSnapshotContext;
  const composed = [ctx?.representativeFirstName, ctx?.representativeLastName].filter(Boolean).join(" ").trim();
  if (composed.length > 0) return composed;
  return "Profiel";
}

function dash(v: string | undefined): string {
  return v != null && v.trim() !== "" ? v : "—";
}

function UserSessionProfileRows({ user }: { user: MockPrototypeUser }) {
  return (
    <>
      <DataRow label="Gebruikers-id" value={user.id} />
      <DataRow label="Weergavenaam" value={user.displayName} />
      <DataRow label="Voornaam" value={user.givenName} />
      <DataRow label="Achternaam" value={user.familyName} />
      <DataRow label="E-mail" value={user.email} />
      <DataRow label="Werk-e-mail" value={dash(user.workEmail)} />
      <DataRow label="Telefoon" value={dash(user.phone)} />
      <DataRow label="Mobiel" value={dash(user.mobilePhone)} />
      <DataRow label="Functietitel" value={dash(user.jobTitle)} />
      <DataRow label="Afdeling" value={dash(user.department)} />
      <DataRow label="Locale" value={dash(user.locale)} />
      <DataRow label="Tijdzone" value={dash(user.timeZone)} />
      <DataRow label="Voorkeurstaal" value={dash(user.preferredLanguage)} />
      <DataRow label="Aanhef" value={dash(user.salutation)} />
      <DataRow label="Personeelsreferentie" value={dash(user.employeeReference)} />
      <DataRow label="Rol" value={dash(user.role)} />
      <DataRow label="Notities" value={dash(user.notes)} />
      <DataRow label="Thuisorganisatie" value={`${user.homeOrganization.name} (${user.homeOrganization.id})`} />
      <DataRow
        label="Vertegenwoordigde organisatie"
        value={`${user.representedOrganization.name} (${user.representedOrganization.id})`}
      />
    </>
  );
}

function OnboardingPersonRows({ context }: { context: CustomerContext }) {
  return (
    <>
      <DataRow label="Voornaam" value={context.representativeFirstName} />
      <DataRow label="Achternaam" value={context.representativeLastName} />
      <DataRow label="Aanhef (preset-id)" value={context.representativeTitlePreset} />
      <DataRow label="Aanhef (tekst)" value={context.representativeTitle} />
      <DataRow label="E-mail" value={context.representativeEmail} />
      <DataRow label="Functie (preset-id)" value={context.representativeRolePreset} />
      <DataRow label="Functie (label)" value={context.representativeRole} />
    </>
  );
}

export function UserProfilePage() {
  const session = useMockPrototypeSession();
  const user = session?.user;
  const patchProfile = useMockPrototypePatchProfile();
  const [storedTick, setStoredTick] = useState(0);
  const stored = useMemo(() => readStoredOnboardingContexts(), [storedTick]);
  const [editOpen, setEditOpen] = useState(false);
  const [form, setForm] = useState<UserEditForm | null>(null);

  const flow = useStepLayout({
    totalSteps: USER_EDIT_STEPS.length,
    canAdvanceFrom: () => true,
  });

  useEffect(() => {
    if (!editOpen || !user) return;
    const flowCtx = stored.flowContext ?? stored.completedSnapshotContext ?? {};
    const { id: _id, homeOrganization, representedOrganization, organizations: _orgs, ...profile } = user;
    setForm({
      ...profile,
      role: profile.role ?? "",
      homeOrgName: homeOrganization.name,
      reprOrgName: representedOrganization.name,
      ...onboardingSlice(flowCtx),
    });
    flow.goToStep(0);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [editOpen, user?.id, stored]);

  const headerIcon = (
    <div className="flex size-10 shrink-0 items-center justify-center rounded-xl bg-primary/8 text-primary">
      <HugeiconsIcon icon={userNav.icon} size={22} strokeWidth={iconStroke(22)} />
    </div>
  );

  const profileTitle = resolveProfilePageTitle(user, stored);

  const handleSave = useCallback(() => {
    if (!user || !form) return;
    const {
      homeOrgName,
      reprOrgName,
      representativeFirstName,
      representativeLastName,
      representativeTitlePreset,
      representativeTitle,
      representativeEmail,
      representativeRolePreset,
      representativeRole,
      ...userFields
    } = form;
    patchProfile({
      user: userFields,
      organizationNames: {
        [user.homeOrganization.id]: homeOrgName,
        [user.representedOrganization.id]: reprOrgName,
      },
    });
    mergeStoredOnboardingCustomerContext({
      representativeFirstName,
      representativeLastName,
      representativeTitlePreset,
      representativeTitle,
      representativeEmail,
      representativeRolePreset,
      representativeRole,
    });
    setStoredTick((n) => n + 1);
    setEditOpen(false);
  }, [user, form, patchProfile]);

  const stepTitle =
    flow.activeStep === 0
      ? "Identiteit"
      : flow.activeStep === 1
        ? "Contact en werkcontext"
        : flow.activeStep === 2
          ? "Organisatienamen"
          : "Vertegenwoordiger (onboarding)";

  const stepDescription =
    flow.activeStep === 0
      ? "Kerngegevens van uw account in deze demo."
      : flow.activeStep === 1
        ? "Optioneel tijdens registratie; hier kunt u ze alsnog aanvullen."
        : flow.activeStep === 2
          ? "Weergavenamen van gekoppelde organisaties (sessie + naamoverride)."
          : "Velden uit de anonieme flow (CustomerContext), los van het accountrecord.";

  return (
    <div className="flex w-full max-w-[1400px] flex-col gap-region px-4 py-6 text-left md:px-6 md:py-8">
      <PageHeader
        icon={headerIcon}
        kicker="Hoofdaccount"
        title={<H1 className="text-balance">{profileTitle}</H1>}
        description="Gegevens van uw prototype-sessie en — indien aanwezig — de velden uit de anonieme onboardingflow (localStorage in deze browser)."
        actions={
          user ? (
            <Button type="button" size="sm" variant="outline" onClick={() => setEditOpen(true)}>
              Gegevens bewerken
            </Button>
          ) : null
        }
      />

      <Dialog open={editOpen} onOpenChange={setEditOpen}>
        <DialogContent className="flex max-h-[min(92vh,820px)] max-w-2xl flex-col gap-0 overflow-hidden p-0 sm:max-w-2xl">
          <DialogHeader className="shrink-0 space-y-2 border-b border-border px-6 pb-4 pt-6">
            <DialogTitle>Profiel bewerken</DialogTitle>
            <DialogDescription>
              Demo: stapsgewijs zoals bij registratie. Sessie- en onboardinggegevens worden in deze browser bewaard.
            </DialogDescription>
          </DialogHeader>
          {form && user ? (
            <form
              className="flex min-h-0 flex-1 flex-col"
              onSubmit={(e) => {
                e.preventDefault();
                if (flow.isLast) handleSave();
              }}
            >
              <StepLayout
                className="min-h-[min(60vh,520px)] flex-1 rounded-none border-0 shadow-none"
                variant="wizard"
                layout="fill-parent"
                flush
                stepKey={flow.activeStep}
                stepper={
                  <OnboardingStepper
                    orientation="horizontal"
