/**
 * Demo model: profile edits in Prosdeptis go through a change request instead of applying immediately.
 * Persisted in localStorage (see storage.ts).
 */

export type ProfileChangeRequestStatus = "submitted" | "validated" | "accepted" | "rejected" | "canceled";

export type ProfileChangeRequestKind = "user" | "organization";

export type ProfileChangeNoteAuthor = "requester" | "processor";

export type ProfileChangeNote = {
  id: string;
  at: string;
  author: ProfileChangeNoteAuthor;
  body: string;
};

/** Flat snapshot for diff / persistence (all string values). */
export type UserProfileChangePayload = Record<string, string>;

/** Mirrors {@link OrgEditForm} in organization profile page — string fields only. */
export type OrganizationProfileChangePayload = Record<string, string> & {
  organizationId: string;
};

export type ProfileChangeRequest = {
  id: string;
  kind: ProfileChangeRequestKind;
  /** Mock user id (session user) for user-profile changes. */
  subjectUserId?: string;
  /** Active organization id for org-profile changes. */
  subjectOrganizationId?: string;
  status: ProfileChangeRequestStatus;
  createdAt: string;
  updatedAt: string;
  title: string;
  baseline: UserProfileChangePayload | OrganizationProfileChangePayload;
  proposed: UserProfileChangePayload | OrganizationProfileChangePayload;
  notes: ProfileChangeNote[];
};

export type ProfileChangeRequestStore = {
  requests: ProfileChangeRequest[];
};

export function isTerminalProfileChangeStatus(s: ProfileChangeRequestStatus): boolean {
  return s === "accepted" || s === "rejected" || s === "canceled";
}

export function isPendingProfileChangeStatus(s: ProfileChangeRequestStatus): boolean {
  return s === "submitted" || s === "validated";
}

import type { ProfileChangeRequest, ProfileChangeRequestStore } from "./types";

export const PROFILE_CHANGE_REQUESTS_STORAGE_KEY = "pt1-profile-change-requests";

function emptyStore(): ProfileChangeRequestStore {
  return { requests: [] };
}

export function readProfileChangeRequestStore(): ProfileChangeRequestStore {
  if (typeof localStorage === "undefined") return emptyStore();
  try {
    const raw = localStorage.getItem(PROFILE_CHANGE_REQUESTS_STORAGE_KEY);
    if (!raw) return emptyStore();
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== "object" || !Array.isArray((parsed as ProfileChangeRequestStore).requests)) {
      return emptyStore();
    }
    return parsed as ProfileChangeRequestStore;
  } catch {
    return emptyStore();
  }
}

export function writeProfileChangeRequestStore(store: ProfileChangeRequestStore): void {
  if (typeof localStorage === "undefined") return;
  try {
    localStorage.setItem(PROFILE_CHANGE_REQUESTS_STORAGE_KEY, JSON.stringify(store));
  } catch {
    /* ignore */
  }
}

export function newChangeNoteId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) return crypto.randomUUID();
  return `n-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

export function newChangeRequestId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) return crypto.randomUUID();
  return `cr-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

/** Shallow flatten for diff display and JSON-safe persistence. */
export function flattenStringRecord(input: Record<string, unknown>): Record<string, string> {
  const out: Record<string, string> = {};
  for (const [k, v] of Object.entries(input)) {
    if (v === undefined || v === null) out[k] = "";
    else if (typeof v === "string") out[k] = v;
    else out[k] = String(v);
  }
  return out;
}

export type FieldDiffRow = { key: string; before: string; after: string };

/** Keys where before !== after; stable sort by key. */
export function diffStringRecords(
  before: Record<string, string>,
  after: Record<string, string>,
): FieldDiffRow[] {
  const keys = new Set([...Object.keys(before), ...Object.keys(after)]);
  const rows: FieldDiffRow[] = [];
  for (const key of keys) {
    const b = before[key] ?? "";
    const a = after[key] ?? "";
    if (b !== a) rows.push({ key, before: b, after: a });
  }
  rows.sort((x, y) => x.key.localeCompare(y.key));
  return rows;
}

export function hasAnyDiff(before: Record<string, string>, after: Record<string, string>): boolean {
  return diffStringRecords(before, after).length > 0;
}

import type { CustomerContext } from "@procertus-ui/ui-certification";
import type {
  MockPrototypeOrganizationProfilePatch,
  PrototypeOrganizationProfile,
  PrototypePostalAddress,
} from "@procertus-ui/ui-pt1-prototype";

/** All fields editable in the organization profile change dialog (demo). */
export type OrgProfileChangeForm = {
  orgName: string;
  demoAddress: string;
  organizationName: string;
  vatNumber: string;
  country: string;
  addressStreet: string;
  addressHouseNumber: string;
  addressPostalCode: string;
  addressCity: string;
  tradeName: string;
  legalName: string;
  enterpriseNumber: string;
  primaryEmail: string;
  primaryPhone: string;
  websiteUrl: string;
  industrySector: string;
  employeeCountApprox: string;
  foundedYear: string;
  regStreet: string;
  regHouse: string;
  regPostal: string;
  regCity: string;
  regCountry: string;
  corrStreet: string;
  corrHouse: string;
  corrPostal: string;
  corrCity: string;
  corrCountry: string;
};

export function recordToOrgProfileForm(r: Record<string, string>): OrgProfileChangeForm {
  const g = (k: keyof OrgProfileChangeForm) => r[k] ?? "";
  return {
    orgName: g("orgName"),
    demoAddress: g("demoAddress"),
    organizationName: g("organizationName"),
    vatNumber: g("vatNumber"),
    country: g("country"),
    addressStreet: g("addressStreet"),
    addressHouseNumber: g("addressHouseNumber"),
    addressPostalCode: g("addressPostalCode"),
    addressCity: g("addressCity"),
    tradeName: g("tradeName"),
    legalName: g("legalName"),
    enterpriseNumber: g("enterpriseNumber"),
    primaryEmail: g("primaryEmail"),
    primaryPhone: g("primaryPhone"),
    websiteUrl: g("websiteUrl"),
    industrySector: g("industrySector"),
    employeeCountApprox: g("employeeCountApprox"),
    foundedYear: g("foundedYear"),
    regStreet: g("regStreet"),
    regHouse: g("regHouse"),
    regPostal: g("regPostal"),
    regCity: g("regCity"),
    regCountry: g("regCountry"),
    corrStreet: g("corrStreet"),
    corrHouse: g("corrHouse"),
    corrPostal: g("corrPostal"),
    corrCity: g("corrCity"),
    corrCountry: g("corrCountry"),
  };
}

export function companySlice(ctx: Partial<CustomerContext> | null | undefined): Pick<
  OrgProfileChangeForm,
  | "organizationName"
  | "vatNumber"
  | "country"
  | "addressStreet"
  | "addressHouseNumber"
  | "addressPostalCode"
  | "addressCity"
> {
  return {
    organizationName: ctx?.organizationName ?? "",
    vatNumber: ctx?.vatNumber ?? "",
    country: ctx?.country ?? "",
    addressStreet: ctx?.addressStreet ?? "",
    addressHouseNumber: ctx?.addressHouseNumber ?? "",
    addressPostalCode: ctx?.addressPostalCode ?? "",
    addressCity: ctx?.addressCity ?? "",
  };
}

export function referenceSliceFromProfile(p: PrototypeOrganizationProfile | undefined): Pick<
  OrgProfileChangeForm,
  | "tradeName"
  | "legalName"
  | "enterpriseNumber"
  | "primaryEmail"
  | "primaryPhone"
  | "websiteUrl"
  | "industrySector"
  | "employeeCountApprox"
  | "foundedYear"
  | "regStreet"
  | "regHouse"
  | "regPostal"
  | "regCity"
  | "regCountry"
  | "corrStreet"
  | "corrHouse"
  | "corrPostal"
  | "corrCity"
  | "corrCountry"
> {
  if (!p) {
    return {
      tradeName: "",
      legalName: "",
      enterpriseNumber: "",
      primaryEmail: "",
      primaryPhone: "",
      websiteUrl: "",
      industrySector: "",
      employeeCountApprox: "",
      foundedYear: "",
      regStreet: "",
      regHouse: "",
      regPostal: "",
      regCity: "",
      regCountry: "",
      corrStreet: "",
      corrHouse: "",
      corrPostal: "",
      corrCity: "",
      corrCountry: "",
    };
  }
  const r = p.registeredAddress;
  const c = p.correspondenceAddress ?? p.registeredAddress;
  return {
    tradeName: p.tradeName,
    legalName: p.legalName,
    enterpriseNumber: p.enterpriseNumber ?? "",
    primaryEmail: p.primaryEmail,
    primaryPhone: p.primaryPhone ?? "",
    websiteUrl: p.websiteUrl ?? "",
    industrySector: p.industrySector ?? "",
    employeeCountApprox: p.employeeCountApprox !== undefined ? String(p.employeeCountApprox) : "",
    foundedYear: p.foundedYear !== undefined ? String(p.foundedYear) : "",
    regStreet: r.street,
    regHouse: r.houseNumber,
    regPostal: r.postalCode,
    regCity: r.city,
    regCountry: r.countryCode,
    corrStreet: c.street,
    corrHouse: c.houseNumber,
    corrPostal: c.postalCode,
    corrCity: c.city,
    corrCountry: c.countryCode,
  };
}

function optionalInt(s: string): number | undefined {
  const t = s.trim();
  if (t === "") return undefined;
  const n = Number(t);
  return Number.isFinite(n) ? n : undefined;
}

function partialPostalFromForm(
  street: string,
  houseNumber: string,
  postalCode: string,
  city: string,
  countryCode: string,
): PrototypePostalAddress | undefined {
  const out = {
    street: street.trim(),
    houseNumber: houseNumber.trim(),
    postalCode: postalCode.trim(),
    city: city.trim(),
    countryCode: countryCode.trim(),
  };
  if (!Object.values(out).some((v) => v.length > 0)) return undefined;
  return out;
}

export function buildOrganizationProfileOverlay(form: OrgProfileChangeForm): MockPrototypeOrganizationProfilePatch {
  const reg = partialPostalFromForm(
    form.regStreet,
    form.regHouse,
    form.regPostal,
    form.regCity,
    form.regCountry,
  );
  const corr = partialPostalFromForm(
    form.corrStreet,
    form.corrHouse,
    form.corrPostal,
    form.corrCity,
    form.corrCountry,
  );
  return {
    tradeName: form.tradeName.trim() || undefined,
    legalName: form.legalName.trim() || undefined,
    enterpriseNumber: form.enterpriseNumber.trim() || undefined,
    primaryEmail: form.primaryEmail.trim() || undefined,
    primaryPhone: form.primaryPhone.trim() || undefined,
    websiteUrl: form.websiteUrl.trim() || undefined,
    industrySector: form.industrySector.trim() || undefined,
    employeeCountApprox: optionalInt(form.employeeCountApprox),
    foundedYear: optionalInt(form.foundedYear),
    vatNumber: form.vatNumber.trim() || undefined,
    ...(reg ? { registeredAddress: reg } : {}),
    ...(corr ? { correspondenceAddress: corr } : {}),
  };
}

import type { MockPrototypeProfilePatch } from "@procertus-ui/ui-pt1-prototype";

import { mergeStoredOnboardingCustomerContext } from "../profile/mergeStoredOnboardingCustomerContext";
import { buildOrganizationProfileOverlay, recordToOrgProfileForm, type OrgProfileChangeForm } from "./org-profile-change";
import { flattenStringRecord } from "./flatten";
import type { OrganizationProfileChangePayload } from "./types";

export function orgFormToChangePayload(
  form: OrgProfileChangeForm,
  organizationId: string,
): OrganizationProfileChangePayload {
  const flat = flattenStringRecord(form as unknown as Record<string, unknown>);
  return { ...flat, organizationId };
}

export function applyOrganizationProfileChange(
  proposed: OrganizationProfileChangePayload,
  deps: {
    organizationId: string;
    patchProfile: (p: MockPrototypeProfilePatch) => void;
    setOrgDemoAddressOverride: (organizationId: string, address: string) => void;
  },
): void {
  const { organizationId, patchProfile, setOrgDemoAddressOverride } = deps;
  const { organizationId: _drop, ...rest } = proposed;
  const form = recordToOrgProfileForm(rest);
  const base = proposed.organizationId
    ? // eslint-disable-next-line @typescript-eslint/no-require-imports -- runtime import avoided; caller passes getPrototypeOrganizationProfile from pt1
      undefined
    : undefined;
  void base;
  void _drop;
  const staticBase = (() => {
    try {
      // Dynamic import would be async; use sync require pattern not available in ESM browser.
      return null;
    } catch {
      return null;
    }
  })();
  void staticBase;
  const profileOverlayBuild = (() => {
    const { getPrototypeOrganizationProfile } = require("@procertus-ui/ui-pt1-prototype") as {
      getPrototypeOrganizationProfile: (id: string) => import("@procertus-ui/ui-pt1-prototype").PrototypeOrganizationProfile | undefined;
    };
    return getPrototypeOrganizationProfile(organizationId);
  })();
  const profileOverlay = profileOverlayBuild ? buildOrganizationProfileOverlay(form) : undefined;
  patchProfile({
    organizationNames: { [organizationId]: form.orgName },
    ...(profileOverlay ? { organizationProfiles: { [organizationId]: profileOverlay } } : {}),
  });
  setOrgDemoAddressOverride(organizationId, form.demoAddress);
  mergeStoredOnboardingCustomerContext({
    organizationName: form.organizationName,
    vatNumber: form.vatNumber,
    country: form.country,
    addressStreet: form.addressStreet,
    addressHouseNumber: form.addressHouseNumber,
    addressPostalCode: form.addressPostalCode,
    addressCity: form.addressCity,
  });
}

