import { HugeiconsIcon } from "@hugeicons/react";
import { FileEditIcon } from "@hugeicons/core-free-icons";
import { Card, CardContent, CardDescription, CardHeader, CardTitle, H1, iconStroke } from "@procertus-ui/ui";
import { PageHeader } from "@procertus-ui/ui-lib";
import { useMockPrototypePatchProfile, useMockPrototypeSession } from "@procertus-ui/ui-pt1-prototype";
import { useCallback, useMemo } from "react";

import { ProfileChangeRequestCard } from "../components/profile-change-requests/ProfileChangeRequestCard";
import { useProfileChangeRequests } from "../features/profile-change-requests/use-profile-change-requests";
import { setOrgDemoAddressOverride } from "../features/profile/prototypeOrgDemoAddresses";

export function ProfileChangeRequestsPage() {
  const session = useMockPrototypeSession();
  const patchProfile = useMockPrototypePatchProfile();
  const { requests, setStatus, appendNote, acceptAndApply } = useProfileChangeRequests();

  const sorted = useMemo(
    () => [...requests].sort((a, b) => b.updatedAt.localeCompare(a.updatedAt)),
    [requests],
  );

  const onValidate = useCallback((id: string) => setStatus(id, "validated"), [setStatus]);
  const onReject = useCallback((id: string) => setStatus(id, "rejected"), [setStatus]);
  const onCancel = useCallback((id: string) => setStatus(id, "canceled"), [setStatus]);

  const onAccept = useCallback(
    (id: string) => {
      const req = requests.find((r) => r.id === id);
      if (!req || !session?.user) return;
      if (req.kind === "user" && req.subjectUserId === session.user.id) {
        acceptAndApply(id, {
          kind: "user",
          patchProfile,
          homeOrganizationId: session.user.homeOrganization.id,
          representedOrganizationId: session.user.representedOrganization.id,
        });
      } else if (req.kind === "organization" && req.subjectOrganizationId) {
        acceptAndApply(id, {
          kind: "organization",
          organizationId: req.subjectOrganizationId,
          patchProfile,
          setOrgDemoAddressOverride,
        });
      }
    },
    [acceptAndApply, patchProfile, requests, session?.user],
  );

  const icon = (
    <div className="flex size-10 shrink-0 items-center justify-center rounded-xl bg-primary/8 text-primary">
      <HugeiconsIcon icon={FileEditIcon as never} size={22} strokeWidth={iconStroke(22)} />
    </div>
  );

  return (
    <div className="flex w-full max-w-[1000px] flex-col gap-region px-4 py-6 text-left md:px-6 md:py-8">
      <PageHeader
        icon={icon}
        kicker="Beheer"
        title={<H1 className="text-balance">Profielwijzigingen</H1>}
        description="Demo: wijzigingsdocumenten voor gebruikers- en organisatieprofielen. Alleen na validatie en acceptatie worden gegevens doorgevoerd (localStorage / sessie)."
      />

      {sorted.length === 0 ? (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Geen wijzigingsaanvragen</CardTitle>
            <CardDescription>Dien een wijziging in via Mijn profiel of Organisatieprofiel.</CardDescription>
          </CardHeader>
        </Card>
      ) : (
        <div className="flex flex-col gap-region">
          {sorted.map((r) => (
            <ProfileChangeRequestCard
              key={r.id}
              request={r}
              onValidate={onValidate}
              onAccept={onAccept}
              onReject={onReject}
              onCancel={onCancel}
              onAddNote={appendNote}
            />
          ))}
        </div>
      )}
    </div>
  );
}

