  requests: ProfileChangeRequest[],
  organizationId: string,
): ProfileChangeRequest | undefined {
  return requests.find(
    (r) =>
      r.kind === "organization" &&
      r.subjectOrganizationId === organizationId &&
      isPendingProfileChangeStatus(r.status),
  );
}

