import type { CertificationRequestLifecycleStepId } from "@procertus-ui/ui-certification";

import type { ProfileChangeRequest } from "./types";

const formatShort = (value: string) =>
  new Intl.DateTimeFormat("nl-BE", {
    day: "numeric",
    month: "short",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date(value));

/** Date hints under the horizontal lifecycle (aligned with certification request cards). */
export function profileChangeTimelineDateLabels(
  request: ProfileChangeRequest,
): Partial<Record<CertificationRequestLifecycleStepId, string>> {
  const labels: Partial<Record<CertificationRequestLifecycleStepId, string>> = {
    submitted: formatShort(request.createdAt),
  };
  if (request.status === "validated") {
    labels["in-progress"] = formatShort(request.updatedAt);
  }
  return labels;
}

import type { CertificationRequestLifecycleEvent } from "@procertus-ui/ui-certification";

import type { ProfileChangeRequest } from "./types";

const formatWhen = (iso: string) =>
  new Intl.DateTimeFormat("nl-BE", {
    day: "numeric",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date(iso));

export function profileChangeDetailLifecycleEvents(request: ProfileChangeRequest): CertificationRequestLifecycleEvent[] {
  const events: CertificationRequestLifecycleEvent[] = [
    {
      id: "submitted",
      title: "Wijzigingsdocument ingediend",
      actorLabel: "Aanvrager",
      occurredAtLabel: formatWhen(request.createdAt),
      description: `${request.kind === "user" ? "Gebruikersprofiel" : "Organisatieprofiel"} — nog niet samengevoegd met de actieve gegevens.`,
    },
  ];

  if (request.status === "validated") {
    events.push({
      id: "validated",
      title: "Gevalideerd door verwerker",
      actorLabel: "Verwerker",
      occurredAtLabel: formatWhen(request.updatedAt),
      description: "Klaar voor definitieve acceptatie en doorvoer.",
      status: "success",
    });
  }

  return events;
}

