  const preview = rows.slice(0, 3);

  return (
    <div className="space-y-3">
      <p className="text-xs text-muted-foreground">
        {rows.length === 1 ? "1 veld gewijzigd" : `${rows.length} velden gewijzigd`}
      </p>
      <ItemGroup className="w-full gap-2">
        {preview.map((row) => (
