import { Cancel01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { Button, CoverView, IconButton, Textarea, usePanelsContext } from "@procertus-ui/ui";
import {
  CertificationRequestLifecycleDetailTimeline,
  CertificationRequestLifecycleTimeline,
} from "@procertus-ui/ui-certification";
import { PanelSection } from "@procertus-ui/ui-lib";
import { useMockPrototypePatchProfile, useMockPrototypeSession } from "@procertus-ui/ui-pt1-prototype";
import { useCallback, useMemo, useState } from "react";

import { diffStringRecords } from "../features/profile-change-requests/flatten";
import { labelForChangeField } from "../features/profile-change-requests/field-labels";
import {
  PROFILE_CHANGE_STATUS_LABEL,
  profileChangeStatusToCertificationTimeline,
} from "../features/profile-change-requests/lifecycle-map";
import { profileChangeDetailLifecycleEvents } from "../features/profile-change-requests/profile-change-lifecycle-events";
import { profileChangeTimelineDateLabels } from "../features/profile-change-requests/profile-change-timeline-labels";
import { readProfileChangeRequestStore } from "../features/profile-change-requests/storage";
import { useProfileChangeRequests } from "../features/profile-change-requests/use-profile-change-requests";
import { isPendingProfileChangeStatus } from "../features/profile-change-requests/types";
import { setOrgDemoAddressOverride } from "../features/profile/prototypeOrgDemoAddresses";

export const PROFILE_CHANGE_DETAIL_PANEL_TYPE = "profileChangeDetail" as const;

export type ProfileChangeDetailPanelProps = {
  panelType?: string;
  requestId: string;
};

function ClosePanelButton({ panelType = PROFILE_CHANGE_DETAIL_PANEL_TYPE }: { panelType?: string }) {
  const { removePanel } = usePanelsContext();
  const CloseIcon = ({ className }: { className?: string }) => (
    <HugeiconsIcon icon={Cancel01Icon} className={className} />
  );

  return (
    <IconButton
      icon={CloseIcon}
      aria-label="Sluit detailpaneel"
      onClick={() => removePanel(panelType)}
      invertColors
    />
  );
}

export function ProfileChangeDetailPanel({ panelType, requestId }: ProfileChangeDetailPanelProps) {
  const { removePanel } = usePanelsContext();
  const session = useMockPrototypeSession();
  const patchProfile = useMockPrototypePatchProfile();
  const { requests, setStatus, appendNote, acceptAndApply } = useProfileChangeRequests();

  const request = useMemo(
    () => requests.find((candidate) => candidate.id === requestId),
    [requests, requestId],
  );

  const [noteRequester, setNoteRequester] = useState("");
  const [noteProcessor, setNoteProcessor] = useState("");

  const rows = useMemo(
    () =>
      request
        ? diffStringRecords(request.baseline as Record<string, string>, request.proposed as Record<string, string>)
        : [],
    [request],
  );

  const timelineStatus = request ? profileChangeStatusToCertificationTimeline(request.status) : "submitted";
  const dateLabels = useMemo(() => (request ? profileChangeTimelineDateLabels(request) : {}), [request]);
  const lifecycleEvents = useMemo(() => (request ? profileChangeDetailLifecycleEvents(request) : []), [request]);

  const pending = request ? isPendingProfileChangeStatus(request.status) : false;

  const onValidate = useCallback((id: string) => setStatus(id, "validated"), [setStatus]);
  const onReject = useCallback(
    (id: string) => {
      setStatus(id, "rejected");
      removePanel(panelType ?? PROFILE_CHANGE_DETAIL_PANEL_TYPE);
    },
    [setStatus, removePanel, panelType],
  );
  const onCancel = useCallback(
    (id: string) => {
      setStatus(id, "canceled");
      removePanel(panelType ?? PROFILE_CHANGE_DETAIL_PANEL_TYPE);
    },
    [setStatus, removePanel, panelType],
  );

  const onAccept = useCallback(
    (id: string) => {
      const req = readProfileChangeRequestStore().requests.find((r) => r.id === id);
      if (!req) return;
      if (req.kind === "user") {
        if (!session?.user) return;
        acceptAndApply(id, {
          kind: "user",
          patchProfile,
          homeOrganizationId: session.user.homeOrganization.id,
          representedOrganizationId: session.user.representedOrganization.id,
        });
      } else if (req.kind === "organization" && req.subjectOrganizationId) {
        acceptAndApply(id, {
          kind: "organization",
          organizationId: req.subjectOrganizationId,
          patchProfile,
          setOrgDemoAddressOverride,
        });
      }
      removePanel(panelType ?? PROFILE_CHANGE_DETAIL_PANEL_TYPE);
    },
    [acceptAndApply, patchProfile, removePanel, session?.user, panelType],
  );

  if (!request) {
    return (
      <CoverView
        title="Wijziging niet gevonden"
        colorScheme="primary"
        primaryAction={<ClosePanelButton panelType={panelType} />}
        className="h-full"
      >
        <div className="p-4 text-sm text-muted-foreground">
          Deze aanvraag is afgerond of bestaat niet meer in deze browser.
        </div>
      </CoverView>
    );
  }

  return (
    <CoverView
      title={PROFILE_CHANGE_STATUS_LABEL[request.status]}
      colorScheme="primary"
      header={<div className="text-sm font-medium leading-snug">{request.title}</div>}
      primaryAction={<ClosePanelButton panelType={panelType} />}
      className="h-full"
    >
      <div className="space-y-10 p-0">
        <PanelSection
          title="Levenscyclus (overzicht)"
          description="Zelfde stappenlogica als bij certificatieaanvragen (demo)."
        >
          <CertificationRequestLifecycleTimeline dateLabels={dateLabels} status={timelineStatus} />
        </PanelSection>

        <PanelSection title="Tijdlijn" description="Belangrijkste stappen op dit wijzigingsdocument.">
          <CertificationRequestLifecycleDetailTimeline events={lifecycleEvents} />
        </PanelSection>

        <PanelSection
          title="Volledige wijzigingen"
          description="Huidige goedgekeurde waarden vergeleken met het ingediende voorstel."
        >
          <div className="overflow-x-auto rounded-md border border-border">
            <table className="w-full min-w-[320px] text-left text-sm">
              <thead className="bg-muted/50">
                <tr>
                  <th className="p-2 font-medium">Veld</th>
                  <th className="p-2 font-medium">Huidig</th>
                  <th className="p-2 font-medium">Voorgesteld</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((row) => (
                  <tr key={row.key} className="border-t border-border">
                    <td className="p-2 align-top text-muted-foreground">{labelForChangeField(row.key)}</td>
                    <td className="p-2 align-top">{row.before || "—"}</td>
                    <td className="p-2 align-top font-medium">{row.after || "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </PanelSection>

        <PanelSection
          title="Conversatie"
          description="Notities van aanvrager en verwerker over deze wijziging."
        >
          {request.notes.length ? (
            <ul className="mb-4 space-y-3 text-sm">
              {request.notes.map((n) => (
                <li key={n.id} className="rounded-md border border-border bg-muted/20 p-3">
                  <span className="text-xs text-muted-foreground">
                    {n.author === "requester" ? "Aanvrager" : "Verwerker"} · {new Date(n.at).toLocaleString()}
                  </span>
                  <p className="whitespace-pre-wrap pt-1">{n.body}</p>
                </li>
              ))}
            </ul>
          ) : (
            <p className="mb-4 text-sm text-muted-foreground">Nog geen notities.</p>
          )}

          {pending ? (
            <div className="grid gap-4 border-t border-border pt-4 sm:grid-cols-2">
              <div className="grid gap-2">
                <p className="text-xs font-semibold text-muted-foreground">Notitie (aanvrager)</p>
                <Textarea value={noteRequester} onChange={(e) => setNoteRequester(e.target.value)} rows={2} />
                <Button
                  type="button"
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    appendNote(request.id, "requester", noteRequester);
                    setNoteRequester("");
                  }}
                >
                  Toevoegen
                </Button>
              </div>
              <div className="grid gap-2">
                <p className="text-xs font-semibold text-muted-foreground">Notitie (verwerker)</p>
                <Textarea value={noteProcessor} onChange={(e) => setNoteProcessor(e.target.value)} rows={2} />
                <Button
                  type="button"
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    appendNote(request.id, "processor", noteProcessor);
                    setNoteProcessor("");
                  }}
                >
                  Toevoegen
                </Button>
              </div>
            </div>
          ) : null}
        </PanelSection>

        {pending ? (
          <PanelSection title="Acties" description="Validatie en acceptatie zoals in het profielproces (demo).">
            <div className="flex flex-wrap gap-2">
              {request.status === "submitted" ? (
                <>
                  <Button type="button" size="sm" onClick={() => onValidate(request.id)}>
                    Valideren (verwerker)
                  </Button>
                  <Button type="button" size="sm" variant="destructive" onClick={() => onReject(request.id)}>
                    Afwijzen
                  </Button>
                  <Button type="button" size="sm" variant="outline" onClick={() => onCancel(request.id)}>
                    Annuleren (aanvrager)
                  </Button>
                </>
              ) : null}
              {request.status === "validated" ? (
                <>
                  <Button type="button" size="sm" onClick={() => onAccept(request.id)}>
                    Accepteren & doorvoeren
                  </Button>
                  <Button type="button" size="sm" variant="destructive" onClick={() => onReject(request.id)}>
                    Afwijzen
                  </Button>
                  <Button type="button" size="sm" variant="outline" onClick={() => onCancel(request.id)}>
                    Annuleren (aanvrager)
                  </Button>
                </>
              ) : null}
            </div>
          </PanelSection>
        ) : null}
      </div>
    </CoverView>
  );
}

