export function hasAnyDiff(before: Record<string, string>, after: Record<string, string>): boolean {
  return diffStringRecords(before, after).length > 0;
}

/** One row per field in baseline ∪ proposed: merged value after apply, and whether it differs from baseline. */
export type MergedFieldRow = {
  key: string;
  baseline: string;
  merged: string;
  changed: boolean;
};

export function mergedProfileFieldRows(
  baseline: Record<string, string>,
  proposed: Record<string, string>,
): MergedFieldRow[] {
  const keys = [...Object.keys(baseline), ...Object.keys(proposed)].filter((k, i, arr) => arr.indexOf(k) === i);
  keys.sort((a, b) => a.localeCompare(b));
  return keys.map((key) => {
    const b = baseline[key] ?? "";
    const hasProposed = Object.prototype.hasOwnProperty.call(proposed, key);
    const merged = hasProposed ? (proposed[key] ?? "") : b;
    const changed = b !== merged;
    return { key, baseline: b, merged, changed };
  });
}

