import { Cancel01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { Button, Badge, CoverView, IconButton, usePanelsContext, cn } from "@procertus-ui/ui";
import {
  CertificationRequestLifecycleDetailTimeline,
  CertificationRequestLifecycleTimeline,
} from "@procertus-ui/ui-certification";
import { PanelSection } from "@procertus-ui/ui-lib";
import { useCallback, useMemo } from "react";

import { diffStringRecords } from "../features/profile-change-requests/flatten";
import { labelForChangeField } from "../features/profile-change-requests/field-labels";
import {
  PROFILE_CHANGE_STATUS_LABEL,
  profileChangeStatusToCertificationTimeline,
} from "../features/profile-change-requests/lifecycle-map";
import { profileChangeDetailLifecycleEvents } from "../features/profile-change-requests/profile-change-lifecycle-events";
import { mockProfileChangePortalThread } from "../features/profile-change-requests/profile-change-mock-portal-thread";
import { profileChangeTimelineDateLabels } from "../features/profile-change-requests/profile-change-timeline-labels";
import { useProfileChangeRequests } from "../features/profile-change-requests/use-profile-change-requests";
import { isPendingProfileChangeStatus } from "../features/profile-change-requests/types";

export const PROFILE_CHANGE_DETAIL_PANEL_TYPE = "profileChangeDetail" as const;

export type ProfileChangeDetailPanelProps = {
  panelType?: string;
  requestId: string;
};

function ClosePanelButton({ panelType = PROFILE_CHANGE_DETAIL_PANEL_TYPE }: { panelType?: string }) {
  const { removePanel } = usePanelsContext();
  const CloseIcon = ({ className }: { className?: string }) => (
    <HugeiconsIcon icon={Cancel01Icon} className={className} />
  );

  return (
    <IconButton
      icon={CloseIcon}
      aria-label="Sluit detailpaneel"
      onClick={() => removePanel(panelType)}
      invertColors
    />
  );
}

function PortalChatPreview() {
  const thread = mockProfileChangePortalThread();
  const fmt = (iso: string) =>
    new Intl.DateTimeFormat("nl-BE", {
      day: "numeric",
      month: "short",
      hour: "2-digit",
      minute: "2-digit",
    }).format(new Date(iso));

  return (
    <div className="flex flex-col gap-3" aria-label="Voorbeeldgesprek met Procertis">
      {thread.map((m) => (
        <div
          key={m.id}
          className={cn("flex w-full", m.side === "requester" ? "justify-end" : "justify-start")}
        >
          <div
            className={cn(
              "max-w-[min(100%,20rem)] rounded-2xl px-3 py-2 text-sm shadow-sm",
              m.side === "requester"
                ? "rounded-br-md bg-primary text-primary-foreground"
                : "rounded-bl-md border border-border bg-card text-foreground",
            )}
          >
            <div className="mb-1 flex flex-wrap items-baseline justify-between gap-x-2 gap-y-0.5 text-[11px] opacity-90">
              <span className="font-semibold">{m.authorLabel}</span>
              <span className="tabular-nums">{fmt(m.atIso)}</span>
            </div>
            <p className="whitespace-pre-wrap leading-snug">{m.body}</p>
          </div>
        </div>
      ))}
      <p className="text-center text-xs text-muted-foreground">
        Voorbeeld — validatie, goedkeuring en notities vanuit Procertis gebeuren in het beheerportaal, niet in dit
        prototype.
      </p>
    </div>
  );
}

export function ProfileChangeDetailPanel({ panelType, requestId }: ProfileChangeDetailPanelProps) {
  const { removePanel } = usePanelsContext();
  const { requests, setStatus } = useProfileChangeRequests();

  const request = useMemo(
    () => requests.find((candidate) => candidate.id === requestId),
    [requests, requestId],
  );

  const diffRows = useMemo(
    () =>
      request
        ? diffStringRecords(request.baseline as Record<string, string>, request.proposed as Record<string, string>)
        : [],
    [request],
  );

  const timelineStatus = request ? profileChangeStatusToCertificationTimeline(request.status) : "submitted";
  const dateLabels = useMemo(() => (request ? profileChangeTimelineDateLabels(request) : {}), [request]);
  const lifecycleEvents = useMemo(() => (request ? profileChangeDetailLifecycleEvents(request) : []), [request]);

  const pending = request ? isPendingProfileChangeStatus(request.status) : false;

  const onCancel = useCallback(
    (id: string) => {
      setStatus(id, "canceled");
      removePanel(panelType ?? PROFILE_CHANGE_DETAIL_PANEL_TYPE);
    },
    [setStatus, removePanel, panelType],
  );

  if (!request) {
    return (
      <CoverView
        title="Wijziging niet gevonden"
        colorScheme="primary"
        primaryAction={<ClosePanelButton panelType={panelType} />}
        className="h-full"
      >
        <div className="p-4 text-sm text-muted-foreground">
          Deze aanvraag is afgerond of bestaat niet meer in deze browser.
        </div>
      </CoverView>
    );
  }

  return (
    <CoverView
      title={PROFILE_CHANGE_STATUS_LABEL[request.status]}
      colorScheme="primary"
      header={<div className="text-sm font-medium leading-snug">{request.title}</div>}
      primaryAction={<ClosePanelButton panelType={panelType} />}
      className="h-full"
    >
      <div className="space-y-10 p-0">
        <PanelSection
          title="Levenscyclus (overzicht)"
          description="Validatie en beslissing gebeuren door Procertis in het beheerportaal (niet in dit extranet-prototype)."
        >
          <CertificationRequestLifecycleTimeline dateLabels={dateLabels} status={timelineStatus} />
        </PanelSection>

        <PanelSection title="Tijdlijn" description="Indicatieve stappen op dit wijzigingsdocument (demo).">
          <CertificationRequestLifecycleDetailTimeline events={lifecycleEvents} />
        </PanelSection>

        <PanelSection
          title="Voorgestelde wijzigingen"
          description="Alleen velden die afwijken van de laatst goedgekeurde waarden."
        >
          <div className="overflow-x-auto rounded-md border border-border">
            <table className="w-full min-w-[320px] text-left text-sm">
              <thead className="bg-muted/50">
                <tr>
                  <th className="p-2 font-medium">Veld</th>
                  <th className="p-2 font-medium">Goedgekeurd (huidig)</th>
                  <th className="p-2 font-medium">Voorgesteld</th>
                </tr>
              </thead>
              <tbody>
                {diffRows.map((row) => (
                  <tr key={row.key} className="border-t border-border bg-primary/5">
                    <td className="p-2 align-top font-medium text-foreground">
                      <span className="inline-flex flex-wrap items-center gap-2">
                        {labelForChangeField(row.key)}
                        <Badge variant="secondary" className="text-[10px] font-normal">
                          wijziging
                        </Badge>
                      </span>
                    </td>
                    <td className="p-2 align-top text-muted-foreground">{row.before || "—"}</td>
                    <td className="p-2 align-top font-medium text-foreground">{row.after || "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </PanelSection>

        <PanelSection
          title="Conversatie (voorbeeld)"
          description="Chat zoals u die later in het extranet zou zien met Procertis. Geen invoer in dit prototype."
        >
          <PortalChatPreview />
        </PanelSection>

        {pending ? (
