/** Who sent the line: extranet user vs PROCERTUS staff (drives bubble alignment and style). */
export type PortalChatMessagePlacement = "requester" | "portal";

export type PortalChatMessage = {
  id: string;
  placement: PortalChatMessagePlacement;
  authorLabel: string;
  /** ISO 8601 timestamp; formatted via `formatTimestamp` or default locale formatter. */
  atIso: string;
  body: string;
};

export type PortalChatComposerProps = {
  /** When false, no composer row is rendered. Default true. */
  show?: boolean;
  readOnly?: boolean;
  placeholder?: string;
  value?: string;
  onChange?: (value: string) => void;
  disabled?: boolean;
  className?: string;
  "aria-label"?: string;
};

export type PortalChatWindowProps = {
  messages: readonly PortalChatMessage[];
  /** Screen reader label for the message list region. */
  "aria-label"?: string;
  className?: string;
  /** Applied to the scroll container around messages (height / max-height). */
  scrollAreaClassName?: string;
  formatTimestamp?: (iso: string) => string;
  /** Optional footer (read-only preview input, textarea, or nothing). */
  composer?: PortalChatComposerProps;
  /** Shown when `messages` is empty instead of the scroll list. */
  emptyContent?: React.ReactNode;
};

import { cn, Input, ScrollArea, Separator } from "@procertus-ui/ui";

import { cn as cnLib } from "@/lib/utils";

import type { PortalChatMessage, PortalChatWindowProps } from "./portal-chat-types";

const defaultFormatTimestamp = (iso: string) =>
  new Intl.DateTimeFormat("nl-BE", {
    day: "numeric",
    month: "short",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date(iso));

function ChatBubble({ message, formatTimestamp }: { message: PortalChatMessage; formatTimestamp: (iso: string) => string }) {
  const isRequester = message.placement === "requester";

  return (
    <div className={cnLib("flex w-full", isRequester ? "justify-end" : "justify-start")}>
      <div
        className={cnLib(
          "max-w-[min(100%,20rem)] rounded-2xl px-3 py-2 text-sm shadow-sm",
          isRequester
            ? "rounded-br-md bg-primary text-primary-foreground"
            : "rounded-bl-md border border-border bg-card text-foreground",
        )}
      >
        <div className="mb-1 flex flex-wrap items-baseline justify-between gap-x-2 gap-y-0.5 text-[11px] opacity-90">
          <span className="font-semibold">{message.authorLabel}</span>
          <span className="tabular-nums">{formatTimestamp(message.atIso)}</span>
        </div>
        <p className="whitespace-pre-wrap leading-snug">{message.body}</p>
      </div>
    </div>
  );
}

/**
 * Read-only or lightly interactive chat transcript for portal detail panels.
 * Uses Shadcn-style primitives from `@procertus-ui/ui` (`ScrollArea`, `Input`, `Separator`).
 * Layout inspired by common “chat” blocks (e.g. shadcn-svelte-extras chat): scrollable transcript + optional composer.
 */
export function PortalChatWindow({
  messages,
  "aria-label": ariaLabel = "Conversatie",
  className,
  scrollAreaClassName,
  formatTimestamp = defaultFormatTimestamp,
  composer,
  emptyContent,
}: PortalChatWindowProps) {
  const showComposer = composer?.show !== false;
  const readOnly = composer?.readOnly ?? true;

  return (
    <div className={cnLib("flex min-w-0 flex-col gap-3", className)}>
      {messages.length === 0 ? (
        <div className="text-sm text-muted-foreground">
          {emptyContent ?? "Nog geen berichten in dit gesprek."}
        </div>
      ) : (
        <ScrollArea
          className={cnLib("max-h-[min(40vh,22rem)] pr-1", scrollAreaClassName)}
          aria-label={ariaLabel}
        >
          <div className="flex flex-col gap-3 pr-2 pb-1" role="log" aria-live="polite">
            {messages.map((m) => (
              <ChatBubble key={m.id} message={m} formatTimestamp={formatTimestamp} />
            ))}
          </div>
        </ScrollArea>
      )}

      {showComposer ? (
        <>
          {messages.length > 0 ? <Separator className="my-0.5" /> : null}
          <div className="min-w-0">
            <Input
              readOnly={readOnly}
              tabIndex={readOnly ? -1 : undefined}
              placeholder={composer?.placeholder ?? "Bericht…"}
              className={cn("bg-background", composer?.className)}
              aria-label={composer?.["aria-label"] ?? composer?.placeholder ?? "Bericht"}
              value={composer?.value}
              onChange={
                composer?.onChange
                  ? (ev) => {
                      composer.onChange?.(ev.target.value);
                    }
                  : undefined
              }
              disabled={composer?.disabled}
            />
          </div>
        </>
      ) : null}
    </div>
  );
}

export type { PortalChatComposerProps, PortalChatMessage, PortalChatMessagePlacement, PortalChatWindowProps } from "./portal-chat-types";

export { PortalChatWindow } from "./PortalChatWindow";
