/** Raw lines for mocked portal chat threads (mapped to `PortalChatMessage` in the conversation panel). */

export type MockPortalChatLine = {
  id: string;
  side: "requester" | "PROCERTUS";
  authorLabel: string;
  atIso: string;
  body: string;
};

export const CONVERSATION_SUITES = ["profileChange", "certification"] as const;
export type ConversationSuite = (typeof CONVERSATION_SUITES)[number];

export const CONVERSATION_SCENARIOS = ["default", "followUp", "short"] as const;
export type ConversationScenario = (typeof CONVERSATION_SCENARIOS)[number];

const PROFILE_DEFAULT: MockPortalChatLine[] = [
  {
    id: "mock-req-1",
    side: "requester",
    authorLabel: "U",
    atIso: "2026-04-28T09:12:00.000Z",
    body: "Hierbij de aangevulde profielgegevens. Kunnen jullie dit valideren wanneer mogelijk?",
  },
  {
    id: "mock-adm-1",
    side: "PROCERTUS",
    authorLabel: "PROCERTUS",
    atIso: "2026-04-28T11:40:00.000Z",
    body: "Ontvangen. We nemen uw wijziging in behandeling en sturen u een update zodra er een beslissing is.",
  },
  {
    id: "mock-adm-2",
    side: "PROCERTUS",
    authorLabel: "PROCERTUS — backoffice",
    atIso: "2026-04-28T14:05:00.000Z",
    body: "Voor de volledigheid: controleer of het BTW-nummer overeenkomt met de KBO-gegevens voordat we definitief doorvoeren.",
  },
];

const PROFILE_FOLLOW_UP: MockPortalChatLine[] = [
  ...PROFILE_DEFAULT,
  {
    id: "mock-req-2",
    side: "requester",
    authorLabel: "U",
    atIso: "2026-04-28T15:30:00.000Z",
    body: "Bedankt — ik heb de KBO-link bijgevoegd in het dossier.",
  },
  {
    id: "mock-adm-3",
    side: "PROCERTUS",
    authorLabel: "PROCERTUS",
    atIso: "2026-04-28T16:02:00.000Z",
    body: "Dank u. We hervatten de controle en melden het resultaat hier.",
  },
];

const PROFILE_SHORT: MockPortalChatLine[] = PROFILE_DEFAULT.slice(0, 2);

const CERT_DEFAULT: MockPortalChatLine[] = [
  {
    id: "cert-req-1",
    side: "requester",
    authorLabel: "U",
    atIso: "2026-04-27T10:05:00.000Z",
    body: "Het aanvraagpakket is ingediend. Graag bevestigen wanneer de intake gepland kan worden.",
  },
  {
    id: "cert-adm-1",
    side: "PROCERTUS",
    authorLabel: "PROCERTUS",
    atIso: "2026-04-27T13:22:00.000Z",
    body: "Ontvangen. Uw dossier staat in de wachtrij voor eerste beoordeling; u ontvangt een seintje zodra er een datum is.",
  },
  {
    id: "cert-adm-2",
    side: "PROCERTUS",
    authorLabel: "PROCERTUS — backoffice",
    atIso: "2026-04-28T08:15:00.000Z",
    body: "Controleer of alle geüploade documenten nog geldig zijn vóór de technische review; verlopen attesten vertragen het traject.",
  },
];

const CERT_FOLLOW_UP: MockPortalChatLine[] = [
  ...CERT_DEFAULT,
  {
    id: "cert-req-2",
    side: "requester",
    authorLabel: "U",
    atIso: "2026-04-29T09:00:00.000Z",
    body: "Documenten zijn vernieuwd; graag opnieuw vrij te geven voor planning.",
  },
  {
    id: "cert-adm-3",
    side: "PROCERTUS",
    authorLabel: "PROCERTUS",
    atIso: "2026-04-29T09:45:00.000Z",
    body: "Noted. Intake wordt opnieuw ingepland zodra de checklist groen is.",
  },
];

const CERT_SHORT: MockPortalChatLine[] = CERT_DEFAULT.slice(0, 2);

const bySuite: Record<ConversationSuite, Record<ConversationScenario, readonly MockPortalChatLine[]>> = {
  profileChange: {
    default: PROFILE_DEFAULT,
    followUp: PROFILE_FOLLOW_UP,
    short: PROFILE_SHORT,
  },
  certification: {
    default: CERT_DEFAULT,
    followUp: CERT_FOLLOW_UP,
    short: CERT_SHORT,
  },
};

export const CONVERSATION_SCENARIO_LABELS: Record<ConversationScenario, string> = {
  default: "Standaard",
  followUp: "Vervolg",
  short: "Kort",
};

export function isConversationSuite(value: string | undefined): value is ConversationSuite {
  return value === "profileChange" || value === "certification";
}

export function isConversationScenario(value: string | undefined): value is ConversationScenario {
  return value === "default" || value === "followUp" || value === "short";
}

export function normalizeConversationScenario(value: string | undefined): ConversationScenario {
  return isConversationScenario(value) ? value : "default";
}

export function getRawConversationThread(
  suite: ConversationSuite,
  scenario: ConversationScenario,
): readonly MockPortalChatLine[] {
  return bySuite[suite][scenario];
}

export function conversationSuiteTitle(suite: ConversationSuite): string {
  return suite === "profileChange" ? "Profielwijziging" : "Certificatieaanvraag";
}

import { Cancel01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import {
  Button,
  CoverView,
  IconButton,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  usePanelsContext,
} from "@procertus-ui/ui";
import { PanelSection, PortalChatWindow, type PortalChatMessage } from "@procertus-ui/ui-lib";
import { useCallback, useMemo } from "react";

import {
  CONVERSATION_SCENARIO_LABELS,
  CONVERSATION_SCENARIOS,
  conversationSuiteTitle,
  getRawConversationThread,
  isConversationSuite,
  normalizeConversationScenario,
  type ConversationScenario,
  type ConversationSuite,
} from "../features/conversations/conversation-detail-panel-mocks";
import type { AppPanelRegistry } from "./panelRegistry";

export const CONVERSATION_DETAIL_PANEL_TYPE = "conversationDetail" as const;

export type ConversationDetailPanelProps = {
  panelType?: string;
  /** Persisted in URL (`panelProps`) when the panel is opened from a detail view. */
  suite: ConversationSuite;
  scenario?: ConversationScenario;
};

function ClosePanelButton({ panelType = CONVERSATION_DETAIL_PANEL_TYPE }: { panelType?: string }) {
  const { removePanel } = usePanelsContext();
  const CloseIcon = ({ className }: { className?: string }) => (
    <HugeiconsIcon icon={Cancel01Icon} className={className} />
  );

  return (
    <IconButton
      icon={CloseIcon}
      aria-label="Sluit conversatiepaneel"
      onClick={() => removePanel(panelType)}
      invertColors
    />
  );
}

function mapLinesToPortalMessages(
  lines: readonly { id: string; side: "requester" | "PROCERTUS"; authorLabel: string; atIso: string; body: string }[],
): PortalChatMessage[] {
  return lines.map((m) => ({
    id: m.id,
    placement: m.side === "requester" ? "requester" : "portal",
    authorLabel: m.authorLabel,
    atIso: m.atIso,
    body: m.body,
  }));
}

export function ConversationDetailPanel({ panelType, suite: suiteProp, scenario: scenarioProp }: ConversationDetailPanelProps) {
  const { openPanel, removePanel } = usePanelsContext<AppPanelRegistry>();
  const suite = isConversationSuite(suiteProp) ? suiteProp : null;
  const scenario = normalizeConversationScenario(scenarioProp);

  const onScenarioChange = useCallback(
    (next: string) => {
      if (!suite) return;
      const normalized = normalizeConversationScenario(next);
      openPanel(CONVERSATION_DETAIL_PANEL_TYPE, { suite, scenario: normalized });
    },
    [openPanel, suite],
  );

  const messages = useMemo(() => {
    if (!suite) return [];
    return mapLinesToPortalMessages(getRawConversationThread(suite, scenario));
  }, [suite, scenario]);

  if (!suite) {
    return (
      <CoverView
        title="Conversatie"
        colorScheme="primary"
        primaryAction={<ClosePanelButton panelType={panelType} />}
        className="h-full"
      >
        <div className="p-4 text-sm text-muted-foreground">Deze conversatie kon niet worden geladen.</div>
      </CoverView>
    );
  }

  const suiteTitle = conversationSuiteTitle(suite);

  return (
    <CoverView
      title="Conversatie"
      colorScheme="primary"
      header={
        <div className="space-y-1">
          <div className="text-sm font-medium leading-snug">{suiteTitle}</div>
          <p className="text-xs text-muted-foreground">
            Scenario staat in de URL; wissel hieronder om andere voorbeeldthreads te bekijken.
          </p>
        </div>
      }
      primaryAction={<ClosePanelButton panelType={panelType} />}
      className="h-full"
    >
      <div className="space-y-8 p-0">
        <PanelSection
          title="Voorbeeldthreads"
          description="Gesprekken zijn gemockt voor dit scherm; kies een scenario om de inhoud te wisselen."
          contentClassName="flex flex-col gap-4"
        >
          <Tabs value={scenario} onValueChange={onScenarioChange} className="w-full min-w-0">
            <TabsList variant="line" className="w-full min-w-0 flex-wrap justify-start">
              {CONVERSATION_SCENARIOS.map((key) => (
                <TabsTrigger key={key} value={key} className="shrink-0">
                  {CONVERSATION_SCENARIO_LABELS[key]}
                </TabsTrigger>
              ))}
            </TabsList>
            {CONVERSATION_SCENARIOS.map((key) => (
              <TabsContent key={key} value={key} className="mt-4 min-w-0">
                {key === scenario ? (
                  <PortalChatWindow
                    aria-label={`Conversatie met PROCERTUS — ${CONVERSATION_SCENARIO_LABELS[key]}`}
                    messages={messages}
                    composer={{
                      readOnly: true,
                      placeholder: "Bericht aan PROCERTUS…",
                      "aria-label": "Bericht aan PROCERTUS",
                    }}
                  />
                ) : null}
              </TabsContent>
            ))}
          </Tabs>
        </PanelSection>

        <PanelSection title="Terug naar dossier" description="Sluit dit paneel of ga verder in het vorige detailvenster.">
          <Button type="button" size="sm" variant="outline" onClick={() => removePanel(panelType ?? CONVERSATION_DETAIL_PANEL_TYPE)}>
            Sluiten
          </Button>
        </PanelSection>
      </div>
    </CoverView>
  );
}

