function ConversationCoverBody({
  panelType,
  suite,
  suiteTitle,
  scenario,
  onScenarioChange,
}: ConversationCoverBodyProps) {
  const [draft, setDraft] = useState("");
  const [optimisticByScenario, setOptimisticByScenario] = useState<
    Partial<Record<ConversationScenario, PortalChatMessage[]>>
  >({});

  useEffect(() => {
    setDraft("");
  }, [scenario, suite]);

  const handleSubmit = useCallback(() => {
    const body = draft.trim();
