      id: `local-${Date.now()}`,
      placement: "requester",
      authorLabel: "U",
      atIso: new Date().toISOString(),
      body,
    };
    setOptimisticByScenario((prev) => ({
      ...prev,
      [scenario]: [...(prev[scenario] ?? []), msg],
    }));
    setDraft("");
  }, [draft, scenario]);

  return (
    <CoverView
      title="Conversatie"
      colorScheme="primary"
      header={<div className="text-sm font-medium leading-snug">{suiteTitle}</div>}
