                  {CONVERSATION_SCENARIO_LABELS[key]}
                </TabsTrigger>
              ))}
            </TabsList>
            {CONVERSATION_SCENARIOS.map((key) => {
              const base = mapLinesToPortalMessages(getRawConversationThread(suite, key));
              const extra = optimisticByScenario[key] ?? [];
              const messages = useMemo(() => [...base, ...extra], [base, extra]);

              return (
                <TabsContent
                  key={key}
