          <Tabs
            value={scenario}
            onValueChange={onScenarioChange}
            className="flex min-h-0 w-full min-w-0 flex-1 flex-col"
          >
            <TabsList variant="line" className="w-full min-w-0 shrink-0 flex-wrap justify-start">
              {CONVERSATION_SCENARIOS.map((key) => (
                <TabsTrigger key={key} value={key} className="shrink-0">
                  {CONVERSATION_SCENARIO_LABELS[key]}
